// FULL-REPLACE GUARD (23 Jun): the SF facts are about to be deleted & re-inserted
// (full-replace) to kill stale orphan grains -- e.g. an open opp dated by CreatedDate
// that later closes moves to a CloseDate grain, leaving its old open-pipeline row
// behind forever under an upsert-only load. Before deleting, abort if the build
// produced 0 rows (e.g. a Salesforce read returned empty), so we never wipe
// fact_channel_daily and leave it empty. Passes the rows through unchanged.
const rows = $('Build Fact Rows').all();
if (rows.length === 0) {
  throw new Error('SF ingest: 0 fact rows built -- aborting before full-replace so fact_channel_daily is never wiped empty.');
}
return rows;

// Re-emit the built fact rows after the delete (the Postgres delete returns no
// items), so the insert below has data -- same pattern as the budget-tracker sync.
return $('Build Fact Rows').all();

// Aggregate Salesforce sources into fact_channel_daily rows at campaign + region + date grain.
// MQL FIX (15 Jun): include CONVERTED leads. On lead conversion Salesforce rewrites the
// CampaignMember to carry ContactId (LeadId becomes null), so the old `WHERE LeadId != null`
// filter dropped ~574 of 580 MQLs. We now resolve members via LeadId OR ConvertedContactId.
const campaigns = $('SF: Get Campaigns').all().map((i) => i.json);
const opps = $('SF: Get Opportunities').all().map((i) => i.json);
const leads = $('SF: Get Leads').all().map((i) => i.json);
const members = $('SF: Get CampaignMembers').all().map((i) => i.json);

// CURRENCY -> EUR (multi-currency org). Convert every amount from its record currency to EUR
// using the org's CurrencyType rates, per-opp BEFORE aggregation. record->corporate = amount /
// rate[iso]; corporate->EUR = x rate['EUR']. Unknown currency -> left as-is. Static (non-dated) rates.
const _rates = {};
for (const c of $('SF: Get Currency Rates').all().map((i) => i.json)) { _rates[c.IsoCode] = Number(c.ConversionRate); }
const _eurRate = _rates['EUR'] || 1;
function toEur(amount, iso) { const a = Number(amount) || 0; const r = _rates[iso]; return (r && isFinite(r)) ? a / r * _eurRate : a; }

// REGION (15 Jun): resolve off SF Lead.Lead_Region__c (leads) / Opportunity.Account.Region__c (opps),
// fallback to Country/BillingCountry. Real region fields are ~86-99% populated vs dirty Country.
function regionFromField(v) {
  const c = String(v || '').trim().toLowerCase();
  if (['united kingdom','uk','gb','great britain','england','scotland','wales','northern ireland','ireland','ie','guernsey','jersey','isle of man'].includes(c)) return 'UKI';
  if (['belgium','bel','be','luxembourg','lux','lu'].includes(c)) return 'BeLux';
  if (['netherlands','nl','the netherlands','holland'].includes(c)) return 'NL';
  return 'UNASSIGNED';
}

const CHANNEL_BY_TYPE = {
  'Event': 'Events & Webinars',
  'Webinar': 'Events & Webinars',
  'Seminar / Conference': 'Events & Webinars',
  'Email': 'Email',
  'Inbound Web': 'Organic SEO',
  'Content/White Paper': 'Organic SEO',
  // TODO(confirm w/ Margot): paid social vs paid search vs organic social
  'Advertisement': 'LinkedIn Paid',
  'Banner Ads': 'LinkedIn Paid',
  'Social Media': 'LinkedIn Paid',
  // 15 Jun (user-approved): non-marketing-channel / unmapped SF Campaign.Type
  // values route to an explicit 'Other / Unmapped' bucket, NOT Organic SEO.
  'Other': 'Other / Unmapped',
  'Telemarketing': 'Other / Unmapped',
  'Partners': 'Other / Unmapped',
  'Referral Program': 'Other / Unmapped'
};
// CHANNEL FIX (15 Jun): all 14 SF Campaign.Type values mapped; unmapped/non-channel -> 'Other / Unmapped' (never Organic SEO). Paid Search has no SF type (no Google Ads campaigns).
function channelForType(type) { return CHANNEL_BY_TYPE[type] || 'Other / Unmapped'; }

// MQL = reached the 'Marketing Qualified Lead' status OR beyond (Margot, Jul 2026 — replaces the
// earlier 'not pre-MQL' exclusion guess). SF has no MQL-date field and Lead.Status is a snapshot, so a
// lead that advanced past MQL keeps a later status — hence 'or beyond'. Statuses at/after MQL on the
// CWSI ladder (per Phase-0 Q2): Marketing Qualified Lead, Meeting Booked, Trial. Converted/qualified
// leads that carry a downstream status are additionally floored up in the app (MQL >= SQL). If CWSI
// adds new post-MQL statuses, list them here.
const MQL_OR_BEYOND = new Set(['Marketing Qualified Lead','Meeting Booked','Trial']);
function isMql(status) { return MQL_OR_BEYOND.has(status); }
const UNQUALIFIED = ['Unqualified opp']; // 5% stage = not a real SQL

const campaignTypeById = {};
for (const c of campaigns) campaignTypeById[c.Id] = c.Type;

// Lead lookup by Lead.Id AND by ConvertedContactId so converted leads stay attributed.
const leadById = {};
const leadByContactId = {};
for (const l of leads) {
  const v = { status: l.Status, region: l.Lead_Region__c || l.Country };
  leadById[l.Id] = v;
  if (l.ConvertedContactId) leadByContactId[l.ConvertedContactId] = v;
}

const agg = {};
function rowFor(campaignKey, region, date) {
  const key = campaignKey + '|' + region + '|' + date;
  if (!agg[key]) {
    agg[key] = {
      campaign_key: campaignKey, region_code: region,
      channel_name: channelForType(campaignTypeById[campaignKey]),
      pillar_name: '', // TODO: pillar not derivable from Campaign.Type; needs name parse or custom field
      activity_date: date, source: 'salesforce',
      spend: 0, impressions: 0, leads: 0, mql_count: 0,
      sql_count: 0, pipeline_value: 0, closed_won_value: 0, margin_value: 0, margin_covered: 0, opp_count: 0, closed_won_count: 0, created_opp_count: 0
    };
  }
  return agg[key];
}

// LEADS + MQL <- CampaignMember joined to Lead (incl. converted leads via ContactId)
for (const m of members) {
  if (!m.CampaignId) continue;
  const date = String(m.CreatedDate || '').slice(0, 10);
  if (!date) continue;
  const lead = (m.LeadId && leadById[m.LeadId]) || (m.ContactId && leadByContactId[m.ContactId]);
  if (!lead) continue; // membership for a pure contact (never a lead) -> not a marketing lead
  const r = rowFor(m.CampaignId, regionFromField(lead.region), date);
  r.leads += 1;
  if (isMql(lead.status)) r.mql_count += 1;
}

// SQL + PIPELINE + CLOSED-WON <- Opportunities
for (const o of opps) {
  if (!o.CampaignId) continue;
  // closed opps dated by CloseDate; open opps by CreatedDate
  const date = String((o.IsClosed ? o.CloseDate : o.CreatedDate) || o.CreatedDate || '').slice(0, 10);
  if (!date) continue;
  const region = o.Account && (o.Account.Region__c || o.Account.BillingCountry);
  const r = rowFor(o.CampaignId, regionFromField(region), date);
  // CREATED OPPORTUNITIES (X3): every opp created in the period, marketing-attributed,
  // regardless of stage/qualification, dated by CreatedDate (its own row if the opp later
  // closed on a different date). Distinct from opp_count (qualified, open/won) and sql_count.
  const createdDate = String(o.CreatedDate || '').slice(0, 10);
  if (createdDate) rowFor(o.CampaignId, regionFromField(region), createdDate).created_opp_count += 1;
  if (!UNQUALIFIED.includes(o.StageName) && (o.IsWon || !o.IsClosed)) r.opp_count += 1; // Opportunities = qualified & (open OR won); excludes unqualified + closed-lost -> subset of SQL
  const amount = toEur(o.Amount, o.CurrencyIsoCode); // EUR
  const qualified = !UNQUALIFIED.includes(o.StageName);
  if (qualified) r.sql_count += 1;                 // every qualified opp = an SQL
  if (o.IsWon) {
    r.closed_won_value += amount; r.closed_won_count += 1;
    // MARGIN (GP): use Gross Profit in EUR. Prefer Gross_Profit_Value__c (profit amount); else
    // Amount x Gross_Profit_Margin__c. Blank both -> incomplete (NULL, never full revenue).
    const _gpv = o.Gross_Profit_Value__c;
    const _gpm = o.Gross_Profit_Margin__c;
    const _hasGpv = _gpv !== null && _gpv !== undefined && _gpv !== '' && !Number.isNaN(Number(_gpv));
    const _hasGpm = _gpm !== null && _gpm !== undefined && _gpm !== '' && !Number.isNaN(Number(_gpm));
    if (_hasGpv) { r.margin_value += toEur(_gpv, o.CurrencyIsoCode); r.margin_covered += 1; }
    else if (_hasGpm) { const _p = Number(_gpm); r.margin_value += amount * (_p > 1 ? _p / 100 : _p); r.margin_covered += 1; }
    // else: this won opp has no gross profit in SF -> it contributes 0 to margin but does NOT void the row (other opps' GP is still used).
  }
  else if (qualified && !o.IsClosed) r.pipeline_value += amount; // open qualified pipeline
}

// spend & impressions are NOT in Salesforce -> stay 0 here (filled by T-3: spend sheet / LinkedIn)
// Use whatever gross profit Salesforce holds (Gross_Profit_Value__c else Amount x Gross_Profit_Margin__c),
// summed per won opp. A won opp with no GP contributes 0; the row's margin is NULL only if NO won opp in it
// carried GP (so partial coverage is kept, not discarded). Zero-cost/100%-margin deals are faithful to SF -> flag to CWSI.
return Object.values(agg).map(({ margin_covered, ...json }) => ({ json: { ...json, margin_value: (json.closed_won_count > 0 && margin_covered === 0) ? null : json.margin_value } }));

const CHANNEL_BY_TYPE = {
  'Event': 'Events & Webinars',
  'Webinar': 'Events & Webinars',
  'Seminar / Conference': 'Events & Webinars',
  'Email': 'Email',
  'Inbound Web': 'Organic SEO',
  'Content/White Paper': 'Organic SEO',
  // TODO(confirm w/ Margot): paid social vs paid search vs organic social
  'Advertisement': 'LinkedIn Paid',
  'Banner Ads': 'LinkedIn Paid',
  'Social Media': 'LinkedIn Paid',
  // 15 Jun (user-approved): non-marketing-channel / unmapped SF Campaign.Type
  // values route to an explicit 'Other / Unmapped' bucket, NOT Organic SEO.
  'Other': 'Other / Unmapped',
  'Telemarketing': 'Other / Unmapped',
  'Partners': 'Other / Unmapped',
  'Referral Program': 'Other / Unmapped'
};
// CHANNEL FIX (15 Jun): all 14 SF Campaign.Type values mapped; unmapped/non-channel -> 'Other / Unmapped' (never Organic SEO). Paid Search has no SF type (no Google Ads campaigns).
function channelForType(type) { return CHANNEL_BY_TYPE[type] || 'Other / Unmapped'; }

// Map Salesforce Campaign records to dim_campaign rows.
return $input.all().map((i) => {
  const c = i.json;
  return { json: {
    campaign_key: c.Id,
    campaign_name: c.Name || null,
    channel_name: channelForType(c.Type),
    campaign_type: c.Type || null,
    start_date: c.StartDate || null,
    parent_id: c.ParentId || null,
    parent_name: (c.Parent && c.Parent.Name) || null,
    source_system: 'salesforce'
  }};
});

// B2 (Path A, 20 Jun): Email SENDS snapshot. This SF org has NO Account Engagement
// (Pardot pi__*) objects and NO ListEmail object, so opens/clicks/delivered cannot
// be queried -- only Campaign.NumberSent. We write ONE snapshot row per EMAIL-type
// campaign with emails_sent set and the rest NULL. Region parsed from campaign name
// (best-effort, like LinkedIn), UNASSIGNED fallback.
function regionFromName(name) {
  const n = String(name || '').toLowerCase();
  if (/uk\/ie|\b(uki|uk|u\.k\.|united kingdom|ireland|ie|irish|gb)\b/.test(n)) return 'UKI';
  if (/\b(belux|belgium|benelux|luxembourg|lux)\b/.test(n)) return 'BeLux';
  if (/\b(nl|netherlands|holland|dutch)\b/.test(n)) return 'NL';
  return 'UNASSIGNED';
}
const today = new Date().toISOString().slice(0, 10);
return $input.all()
  .map((i) => i.json)
  .filter((c) => c.Type === 'Email') // Email-channel campaigns only (matches the Email page)
  .map((c) => ({ json: {
    campaign_key: c.Id,
    region_code: regionFromName(c.Name),
    snapshot_date: today,
    emails_sent: Number(c.NumberSent) || 0,
    emails_delivered: null,
    email_opens: null,
    email_clicks: null
  }}))
  // Path A (20 Jun): no Account Engagement (pi__) objects + no ListEmail in this org,
  // so opens/clicks/delivered are NOT in Salesforce -> NULL (not 0). Keep rows with sends.
  .filter((r) => r.json.emails_sent > 0);

// B3 (19 Jun): Retention/expansion snapshot. Opportunity.Type in
// Renewal/Upsell/Cross-Sell. Renewals are account-based, NOT campaign-attributed,
// so they get their own region+date fact (never fact_channel_daily). Won deals
// (IsWon) = contracts retained/expanded; open qualified deals = renewal pipeline.
function regionFromField(v) {
  const c = String(v || '').trim().toLowerCase();
  if (['united kingdom','uk','gb','great britain','england','scotland','wales','northern ireland','ireland','ie','guernsey','jersey','isle of man'].includes(c)) return 'UKI';
  if (['belgium','bel','be','luxembourg','lux','lu'].includes(c)) return 'BeLux';
  if (['netherlands','nl','the netherlands','holland'].includes(c)) return 'NL';
  return 'UNASSIGNED';
}
const UNQUALIFIED = ['Unqualified opp'];
const TYPES = ['Renewal','Upsell','Cross-Sell'];
const opps = $input.all().map((i) => i.json);

// CURRENCY -> EUR (multi-currency org). Convert every amount from its record currency to EUR
// using the org's CurrencyType rates, per-opp BEFORE aggregation. record->corporate = amount /
// rate[iso]; corporate->EUR = x rate['EUR']. Unknown currency -> left as-is. Static (non-dated) rates.
const _rates = {};
for (const c of $('SF: Get Currency Rates').all().map((i) => i.json)) { _rates[c.IsoCode] = Number(c.ConversionRate); }
const _eurRate = _rates['EUR'] || 1;
function toEur(amount, iso) { const a = Number(amount) || 0; const r = _rates[iso]; return (r && isFinite(r)) ? a / r * _eurRate : a; }
const agg = {};
function rowFor(region, date, type) {
  const key = region + '|' + date + '|' + type;
  if (!agg[key]) agg[key] = { region_code: region, activity_date: date, opp_type: type, won_count: 0, won_value: 0, open_count: 0, open_value: 0 };
  return agg[key];
}
for (const o of opps) {
  if (!TYPES.includes(o.Type)) continue;
  const date = String((o.IsClosed ? o.CloseDate : o.CreatedDate) || o.CreatedDate || '').slice(0, 10);
  if (!date) continue;
  const region = o.Account && (o.Account.Region__c || o.Account.BillingCountry);
  const r = rowFor(regionFromField(region), date, o.Type);
  const amount = toEur(o.Amount, o.CurrencyIsoCode); // EUR
  if (o.IsWon) { r.won_count += 1; r.won_value += amount; }
  else if (!o.IsClosed && !UNQUALIFIED.includes(o.StageName)) { r.open_count += 1; r.open_value += amount; }
}
return Object.values(agg).map((json) => ({ json }));

// B7 (20 Jun): Meetings booked from SF Event (Type='Meeting'). Activities, not
// campaign-attributed, so they get their own region+date fact (fact_meeting_daily),
// mirroring renewals. Region resolves off the polymorphic What (Account direct /
// Opportunity->Account via TYPEOF), then the meeting's Who (Lead, reusing the
// already-fetched Leads) as fallback, else UNASSIGNED. DEDUPE: one meeting may be
// logged once per internal owner with the same Subject/day/Who/What -> count those
// as a single meeting (Owner excluded from the key). 'Booked' = ALL sales meetings
// (Event has no Outreach-source field, so Outreach-only can't be isolated).
function regionFromField(v) {
  const c = String(v || '').trim().toLowerCase();
  if (['united kingdom','uk','gb','great britain','england','scotland','wales','northern ireland','ireland','ie','guernsey','jersey','isle of man'].includes(c)) return 'UKI';
  if (['belgium','bel','be','luxembourg','lux','lu'].includes(c)) return 'BeLux';
  if (['netherlands','nl','the netherlands','holland'].includes(c)) return 'NL';
  return 'UNASSIGNED';
}
const meetings = $('SF: Get Meetings').all().map((i) => i.json);
// Lead region by Lead Id (reuse the already-fetched Leads) for What-blank meetings.
const leadRegionById = {};
for (const l of $('SF: Get Leads').all().map((i) => i.json)) leadRegionById[l.Id] = l.Lead_Region__c || l.Country;
function regionForMeeting(m) {
  const w = m.What; // TYPEOF: Account -> {Region__c,BillingCountry}; Opportunity -> {Account:{...}}
  if (w) {
    if (w.Region__c || w.BillingCountry) return regionFromField(w.Region__c || w.BillingCountry);
    if (w.Account && (w.Account.Region__c || w.Account.BillingCountry)) return regionFromField(w.Account.Region__c || w.Account.BillingCountry);
  }
  if (m.WhoId && leadRegionById[m.WhoId]) return regionFromField(leadRegionById[m.WhoId]);
  return 'UNASSIGNED';
}
const seen = {};
const agg = {};
for (const m of meetings) {
  const day = String(m.ActivityDate || '').slice(0, 10);
  if (!day) continue;
  const k = [m.Subject || '', day, m.WhoId || '', m.WhatId || ''].join('|');
  if (seen[k]) continue; // drop per-attendee duplicate of the same meeting
  seen[k] = true;
  const region = regionForMeeting(m);
  const key = region + '|' + day;
  if (!agg[key]) agg[key] = { region_code: region, activity_date: day, meeting_count: 0 };
  agg[key].meeting_count += 1;
}
return Object.values(agg).map((json) => ({ json }));

// fact_opportunity_stage (Option 1, 20 Jun): OPEN-pipeline snapshot. Count + sum(Amount)
// of open opportunities grouped by StageName x region, as of today. Closed deals are
// excluded here (already covered by the funnel's closed-won). Region via Account.Region__c
// (fixed hop, fallback BillingCountry), UNASSIGNED otherwise. One snapshot per run
// (snapshot_date = today); the upsert grain keeps a row per region x date x stage so
// older snapshots persist (a stepping stone to Option-2 trends later).
function regionFromField(v) {
  const c = String(v || '').trim().toLowerCase();
  if (['united kingdom','uk','gb','great britain','england','scotland','wales','northern ireland','ireland','ie','guernsey','jersey','isle of man'].includes(c)) return 'UKI';
  if (['belgium','bel','be','luxembourg','lux','lu'].includes(c)) return 'BeLux';
  if (['netherlands','nl','the netherlands','holland'].includes(c)) return 'NL';
  return 'UNASSIGNED';
}
const today = new Date().toISOString().slice(0, 10);
const opps = $input.all().map((i) => i.json);

// CURRENCY -> EUR (multi-currency org). Convert every amount from its record currency to EUR
// using the org's CurrencyType rates, per-opp BEFORE aggregation. record->corporate = amount /
// rate[iso]; corporate->EUR = x rate['EUR']. Unknown currency -> left as-is. Static (non-dated) rates.
const _rates = {};
for (const c of $('SF: Get Currency Rates').all().map((i) => i.json)) { _rates[c.IsoCode] = Number(c.ConversionRate); }
const _eurRate = _rates['EUR'] || 1;
function toEur(amount, iso) { const a = Number(amount) || 0; const r = _rates[iso]; return (r && isFinite(r)) ? a / r * _eurRate : a; }
const agg = {};
for (const o of opps) {
  const stage = o.StageName || 'Unknown';
  const region = regionFromField(o.Account && (o.Account.Region__c || o.Account.BillingCountry));
  const key = region + '|' + stage;
  if (!agg[key]) agg[key] = { region_code: region, snapshot_date: today, stage_name: stage, probability: (o.Probability == null ? null : Number(o.Probability)), opp_count: 0, opp_value: 0 };
  if (o.Probability != null) agg[key].probability = Number(o.Probability); // constant per stage
  agg[key].opp_count += 1;
  agg[key].opp_value += toEur(o.Amount, o.CurrencyIsoCode); // EUR
}
return Object.values(agg).map((json) => ({ json }));

// CC-6: SF meetings at per-CONTACT identity grain -> fact_meeting (carries the contact
// email so meetings can be joined to Outreach prospects). ADDITIVE: the aggregated
// fact_meeting_daily branch (Build Meeting Rows) is untouched and keeps running.
// One row per Event.Id; email lowercased for the join. Region reuses the SAME polymorphic
// What/Who resolution as Build Meeting Rows so both branches agree.
function regionFromField(v) {
  const c = String(v || '').trim().toLowerCase();
  if (['united kingdom','uk','gb','great britain','england','scotland','wales','northern ireland','ireland','ie','guernsey','jersey','isle of man'].includes(c)) return 'UKI';
  if (['belgium','bel','be','luxembourg','lux','lu'].includes(c)) return 'BeLux';
  if (['netherlands','nl','the netherlands','holland'].includes(c)) return 'NL';
  return 'UNASSIGNED';
}
const meetings = $('SF: Get Meetings').all().map((i) => i.json);
const leadRegionById = {};
for (const l of $('SF: Get Leads').all().map((i) => i.json)) leadRegionById[l.Id] = l.Lead_Region__c || l.Country;
function regionForMeeting(m) {
  const w = m.What;
  if (w) {
    if (w.Region__c || w.BillingCountry) return regionFromField(w.Region__c || w.BillingCountry);
    if (w.Account && (w.Account.Region__c || w.Account.BillingCountry)) return regionFromField(w.Account.Region__c || w.Account.BillingCountry);
  }
  if (m.WhoId && leadRegionById[m.WhoId]) return regionFromField(leadRegionById[m.WhoId]);
  return 'UNASSIGNED';
}
const out = [];
const seen = {};
for (const m of meetings) {
  if (!m.Id || seen[m.Id]) continue;
  seen[m.Id] = true;
  const day = String(m.ActivityDate || '').slice(0, 10) || null;
  // TYPEOF Who returns the email nested on the Who object for the matched type.
  const email = (m.Who && m.Who.Email ? String(m.Who.Email) : '').trim().toLowerCase() || null;
  out.push({ json: {
    meeting_id: String(m.Id),
    subject: m.Subject || null,
    activity_date: day,
    who_id: m.WhoId || null,
    contact_email: email,
    region_code: regionForMeeting(m)
  }});
}
return out;
